class ImageProcessingController < ApplicationController
  def convert_image
    uploaded_image = params[:image]
    format = params[:format]
    size = params[:size]

    converted_image_path = Rails.root.join('public', 'uploads', "#{SecureRandom.uuid}.#{format}")
    original_image_path = Rails.root.join('public', 'uploads', uploaded_image.original_filename)

    File.open(original_image_path, 'wb') do |file|
      file.write(uploaded_image.read)
    end

    `convert #{original_image_path} -resize #{size} #{converted_image_path}`

    send_file converted_image_path
  end
end